INSERT INTO topics (exam_track_id, title, description, display_order, official_weight_percent, official_blueprint_text)
SELECT et.id, source.title, source.description, source.display_order, source.weight, source.official_blueprint_text
FROM source
JOIN exam_tracks et ON et.slug = source.slug
WHERE NOT EXISTS (
  SELECT 1 FROM topics existing
  WHERE existing.exam_track_id = et.id
    AND existing.title = source.title
);

