UPDATE topics target
SET
  description = source.description,
  official_weight_percent = source.weight,
  official_blueprint_text = source.official_blueprint_text
FROM source
JOIN exam_tracks et ON et.slug = source.slug
WHERE target.exam_track_id = et.id
  AND target.title = source.title;

