INSERT INTO social_work_blueprint_items (
  exam_track_id,
  topic_id,
  exam_level,
  major_content_area,
  percentage_weight,
  competency_section,
  applied_knowledge_statement,
  cognitive_level_guidance,
  official_blueprint_text,
  sample_style_guidance,
  display_order
)
SELECT
  et.id,
  topics.id,
  source.exam_level,
  source.major_content_area,
  source.percentage_weight,
  source.competency_section,
  source.applied_knowledge_statement,
  source.cognitive_level_guidance,
  source.official_blueprint_text,
  source.sample_style_guidance,
  source.display_order
FROM source
JOIN exam_tracks et ON et.slug = source.slug
LEFT JOIN topics ON topics.exam_track_id = et.id AND topics.title = source.major_content_area
ON CONFLICT (exam_track_id, major_content_area, competency_section, applied_knowledge_statement)
DO UPDATE SET
  topic_id = EXCLUDED.topic_id,
  exam_level = EXCLUDED.exam_level,
  percentage_weight = EXCLUDED.percentage_weight,
  cognitive_level_guidance = EXCLUDED.cognitive_level_guidance,
  official_blueprint_text = EXCLUDED.official_blueprint_text,
  sample_style_guidance = EXCLUDED.sample_style_guidance,
  display_order = EXCLUDED.display_order;

-- Legacy questions do not have a selected applied-knowledge record. Preserve
-- their existing topic/subtopic/objective metadata so the checker and review UI
-- still have useful blueprint context instead of blank Social Work fields.
UPDATE questions q
SET
  blueprint_content_area = COALESCE(q.blueprint_content_area, t.title),
  blueprint_competency_section = COALESCE(
    q.blueprint_competency_section,
    NULLIF((SELECT st.title FROM subtopics st WHERE st.id = q.subtopic_id), ''),
    NULLIF(q.subtopic, ''),
    t.title
  ),
  applied_knowledge_statement = COALESCE(
    q.applied_knowledge_statement,
    NULLIF(q.learning_objective, ''),
    NULLIF((SELECT st.learning_objective FROM subtopics st WHERE st.id = q.subtopic_id), '')
  ),
  question_writing_guideline = COALESCE(
    q.question_writing_guideline,
    'Legacy item: verify manually against the stored topic/subtopic blueprint before publishing.'
  ),
  intended_cognitive_level = COALESCE(q.intended_cognitive_level, q.cognitive_level),
  blueprint_reference_text = COALESCE(
    NULLIF(q.blueprint_reference_text, ''),
    NULLIF((SELECT st.official_blueprint_text FROM subtopics st WHERE st.id = q.subtopic_id), ''),
    NULLIF(t.official_blueprint_text, ''),
    NULLIF(q.learning_objective, ''),
    NULLIF(q.subtopic, ''),
    t.title
  )
FROM topics t
WHERE q.topic_id = t.id
  AND q.social_work_blueprint_item_id IS NULL;
